class Solution(object):
    def maxTotalReward(self, rewardValues):
        vals = sorted(set(rewardValues))
        # dp: set of achievable totals
        # For each value v (in order), we can add it if current total < v.
        # dp[j] = True means total j is achievable.
        # Max possible total < 2 * max_val.
        max_val = vals[-1]
        dp = [False] * (2 * max_val)
        dp[0] = True

        for v in vals:
            # For each reachable total x < v, we can reach x + v
            # Process in reverse to avoid using v twice
            for x in range(v - 1, -1, -1):
                if dp[x]:
                    dp[x + v] = True

        for j in range(2 * max_val - 1, -1, -1):
            if dp[j]:
                return j
        return 0
